mapper.select:
SELECT
-- 级联表的字段 ,cheliang.shangjia_id as cheliangShangjiaId ,cheliang.cheliang_name as cheliangName ,cheliang.cheliang_photo as cheliangPhoto ,cheliang.cheliang_types as cheliangTypes ,cheliang.cheliang_new_money as cheliangNewMoney ,cheliang.shangxia_types as shangxiaTypes ,cheliang.cheliang_delete as cheliangDelete ,yonghu.yonghu_name as yonghuName ,yonghu.yonghu_phone as yonghuPhone ,yonghu.yonghu_id_number as yonghuIdNumber ,yonghu.yonghu_photo as yonghuPhoto ,yonghu.yonghu_email as yonghuEmail ,shangjia.shangjia_name as shangjiaName ,shangjia.shangjia_phone as shangjiaPhone ,shangjia.shangjia_email as shangjiaEmail
FROM cheliang_cart a left JOIN cheliang cheliang ON a.cheliang_id = cheliang.id left JOIN yonghu yonghu ON a.yonghu_id = yonghu.id left JOIN shangjia shangjia ON cheliang.shangjia_id = shangjia.id
and a.id in
#{item}
and a.cheliang_id = #{params.cheliangId}
and a.yonghu_id = #{params.yonghuId}
and UNIX_TIMESTAMP(a.insert_time) >= UNIX_TIMESTAMP(#{params.insertTimeStart})
and UNIX_TIMESTAMP(a.insert_time) <= UNIX_TIMESTAMP(#{params.insertTimeEnd})
and cheliang.cheliang_name like CONCAT('%',#{params.cheliangName},'%')
and cheliang.shangjia_id = #{params.shangjiaId}
and cheliang.cheliang_types = #{params.cheliangTypes}
order by a.${params.orderBy} desc
